func fetchModelCatalog(ctx context.Context, c *client.Client) (modelCatalog, error) {
	merged := map[string]xaiModelInfo{}
	var order []string
	var warnings []string
	for _, endpoint := range modelEndpoints {
		data, err := c.GetNoCache(ctx, endpoint.Path, nil)
		if err != nil {
			if endpoint.Family == "catalog" {
				return modelCatalog{}, err
			}
			warnings = append(warnings, fmt.Sprintf("%s unavailable: %v", endpoint.Path, err))
			continue
		}
		models, err := parseModelList(data, endpoint.Key)
		if err != nil {
			warnings = append(warnings, fmt.Sprintf("%s parse skipped: %v", endpoint.Path, err))
			continue
		}
		for _, model := range models {
			if model.ID == "" {
				continue
			}
			if _, ok := merged[model.ID]; !ok {
				order = append(order, model.ID)
			}
			model.Families = append(model.Families, endpoint.Family)
			existing := merged[model.ID]
			merged[model.ID] = mergeModelInfo(existing, model)
		}
	}
	out := make([]xaiModelInfo, 0, len(order))
	for _, id := range order {
		model := merged[id]
		model.Families = uniqueStrings(model.Families)
		model.InputModalities = uniqueStrings(model.InputModalities)
		model.OutputModalities = uniqueStrings(model.OutputModalities)
		model.Aliases = uniqueStrings(model.Aliases)
		model.Capabilities, model.CapabilityConfidence = deriveCapabilities(model)
		model.EstimatedPromptCentsPerMillionTokens = centsPerMillionFromCentsPer100M(model.PromptTextTokenPrice)
		model.EstimatedPromptDollarsPerMillionTokens = model.EstimatedPromptCentsPerMillionTokens / 100
		model.EstimatedOutputCentsPerMillionTokens = centsPerMillionFromCentsPer100M(model.CompletionTextTokenPrice)
		model.EstimatedOutputDollarsPerMillionTokens = model.EstimatedOutputCentsPerMillionTokens / 100
		model.EstimatedChatCentsPerMillionTokens = model.EstimatedPromptCentsPerMillionTokens + model.EstimatedOutputCentsPerMillionTokens
		model.EstimatedChatDollarsPerMillionTokens = model.EstimatedChatCentsPerMillionTokens / 100
		out = append(out, model)
	}
	sort.SliceStable(out, func(i, j int) bool { return out[i].ID < out[j].ID })
	return modelCatalog{Models: out, Warnings: warnings}, nil
}

func parseModelList(data json.RawMessage, preferredKey string) ([]xaiModelInfo, error) {
	var direct []xaiModelInfo
	if err := json.Unmarshal(data, &direct); err == nil && direct != nil {
		return direct, nil
	}
	var envelope map[string]json.RawMessage
	if err := json.Unmarshal(data, &envelope); err != nil {
		return nil, err
	}
	keys := []string{preferredKey, "data", "models"}
	for _, key := range keys {
		raw, ok := envelope[key]
		if !ok {
			continue
		}
		var models []xaiModelInfo
		if err := json.Unmarshal(raw, &models); err != nil {
			return nil, err
		}
		return models, nil
	}
	return nil, fmt.Errorf("no model array found")
}

func mergeModelInfo(a, b xaiModelInfo) xaiModelInfo {
	if a.ID == "" {
		a.ID = b.ID
	}
	if a.OwnedBy == "" {
		a.OwnedBy = b.OwnedBy
	}
	if a.Version == "" {
		a.Version = b.Version
	}
	if a.Created == 0 {
		a.Created = b.Created
	}
	a.InputModalities = append(a.InputModalities, b.InputModalities...)
	a.OutputModalities = append(a.OutputModalities, b.OutputModalities...)
	a.Aliases = append(a.Aliases, b.Aliases...)
	a.Families = append(a.Families, b.Families...)
	if a.PromptTextTokenPrice == 0 {
		a.PromptTextTokenPrice = b.PromptTextTokenPrice
	}
	if a.CachedPromptTextTokenPrice == 0 {
		a.CachedPromptTextTokenPrice = b.CachedPromptTextTokenPrice
	}
	if a.PromptImageTokenPrice == 0 {
		a.PromptImageTokenPrice = b.PromptImageTokenPrice
	}
	if a.CompletionTextTokenPrice == 0 {
		a.CompletionTextTokenPrice = b.CompletionTextTokenPrice
	}
	if a.PromptTextTokenPriceLongContext == 0 {
		a.PromptTextTokenPriceLongContext = b.PromptTextTokenPriceLongContext
	}
	if a.CachedPromptTextTokenPriceLongContext == 0 {
		a.CachedPromptTextTokenPriceLongContext = b.CachedPromptTextTokenPriceLongContext
	}
	if a.CompletionTextTokenPriceLongContext == 0 {
		a.CompletionTextTokenPriceLongContext = b.CompletionTextTokenPriceLongContext
	}
	if a.LongContextThreshold == 0 {
		a.LongContextThreshold = b.LongContextThreshold
	}
	if a.SearchPrice == 0 {
		a.SearchPrice = b.SearchPrice
	}
	if a.ImagePrice == 0 {
		a.ImagePrice = b.ImagePrice
	}
	return a
}

func deriveCapabilities(model xaiModelInfo) ([]string, string) {
	caps := map[string]bool{}
	confidence := "metadata"
	hasTextIn := containsString(model.InputModalities, "text") || len(model.InputModalities) == 0
	hasTextOut := containsString(model.OutputModalities, "text")
	if containsString(model.Families, "language") || (hasTextIn && hasTextOut) {
		caps["chat"] = true
	}
	if containsString(model.InputModalities, "image") && hasTextOut {
		caps["vision"] = true
	}
	if containsString(model.Families, "embedding") || containsString(model.OutputModalities, "embedding") {
		caps["embedding"] = true
	}
	if containsString(model.Families, "image") || containsString(model.OutputModalities, "image") {
		caps["image"] = true
	}
	if containsString(model.Families, "video") || containsString(model.OutputModalities, "video") {
		caps["video"] = true
	}
	if modelLooksReasoning(model) {
		caps["reasoning"] = true
		if !caps["chat"] {
			caps["chat"] = true
		}
	}
	if len(caps) == 0 {
		confidence = "id-heuristic"
		id := strings.ToLower(model.ID)
		switch {
		case strings.Contains(id, "image"):
			caps["image"] = true
		case strings.Contains(id, "video"):
			caps["video"] = true
		case strings.Contains(id, "embed"):
			caps["embedding"] = true
		default:
			caps["chat"] = true
		}
	}
	out := make([]string, 0, len(caps))
	for cap := range caps {
		out = append(out, cap)
	}
	sort.Strings(out)
	return out, confidence
}

type modelRecommendation struct {
	Model             string   `json:"model"`
	Score             int      `json:"score"`
	Capabilities      []string `json:"capabilities"`
	Families          []string `json:"families,omitempty"`
	EstimatedUnitCost string   `json:"estimated_unit_cost,omitempty"`
	Why               []string `json:"why"`
}

func rankModelsForTask(models []xaiModelInfo, task, prefer string, limit int) []modelRecommendation {
	if limit <= 0 {
		limit = 5
	}
	recs := make([]modelRecommendation, 0, len(models))
	for _, model := range models {
		if !containsString(model.Capabilities, task) {
			continue
		}
		score := 100
		var why []string
		why = append(why, "matches "+task)
		if model.CapabilityConfidence == "metadata" {
			score += 20
			why = append(why, "capability from live metadata")
		}
		if task == "reasoning" && modelLooksReasoning(model) {
			score += 20
			why = append(why, "reasoning model name/alias")
		}
		if task == "chat" && strings.Contains(strings.ToLower(model.ID), "non-reasoning") {
			score += 8
			why = append(why, "non-reasoning chat variant")
		}
		cost := modelCostSortValue(model, task)
		if cost > 0 {
			score += int(math.Max(0, 20-math.Min(20, cost/1000)))
			if prefer == "cheap" {
				score += int(math.Max(0, 30-math.Min(30, cost/500)))
			}
		}
		if prefer == "latest" && model.Created > 0 {
			why = append(why, "newer model creation timestamp")
		}
		recs = append(recs, modelRecommendation{
			Model:             model.ID,
			Score:             score,
			Capabilities:      model.Capabilities,
			Families:          model.Families,
			EstimatedUnitCost: describeUnitCost(model, task),
			Why:               why,
		})
	}
	sort.SliceStable(recs, func(i, j int) bool {
		if prefer == "latest" {
			leftCreated := modelCreatedByID(models, recs[i].Model)
			rightCreated := modelCreatedByID(models, recs[j].Model)
			if leftCreated != rightCreated {
				return leftCreated > rightCreated
			}
		}
		if recs[i].Score != recs[j].Score {
			return recs[i].Score > recs[j].Score
		}
		return recs[i].Model < recs[j].Model
	})
	if len(recs) > limit {
		recs = recs[:limit]
	}
	return recs
}

func modelCreatedByID(models []xaiModelInfo, id string) int64 {
	for _, model := range models {
		if model.ID == id {
			return model.Created
		}
	}
	return 0
}

func selectCostModel(models []xaiModelInfo, modelID, task string) (xaiModelInfo, []string, error) {
	if modelID != "" {
		for _, model := range models {
			if model.ID == modelID || containsString(model.Aliases, modelID) {
				return model, nil, nil
			}
		}
		return xaiModelInfo{}, nil, fmt.Errorf("model %q not found in authenticated catalog", modelID)
	}
	recs := rankModelsForTask(models, task, "cheap", 1)
	if len(recs) == 0 {
		return xaiModelInfo{}, nil, fmt.Errorf("no model found for task %q", task)
	}
	for _, model := range models {
		if model.ID == recs[0].Model {
			return model, []string{fmt.Sprintf("no --model supplied; selected %s for task %s", model.ID, task)}, nil
		}
	}
	return xaiModelInfo{}, nil, fmt.Errorf("selected model disappeared from catalog")
}

type costPreview struct {
	Model             string         `json:"model"`
	InputTokens       int64          `json:"input_tokens"`
	CachedInputTokens int64          `json:"cached_input_tokens"`
	OutputTokens      int64          `json:"output_tokens"`
	ImageInputTokens  int64          `json:"image_input_tokens"`
	LongContext       bool           `json:"long_context"`
	EstimatedCents    float64        `json:"estimated_cents"`
	EstimatedUSD      float64        `json:"estimated_usd"`
	PriceFields       map[string]any `json:"price_fields"`
	Warnings          []string       `json:"warnings,omitempty"`
}

func estimateModelCost(model xaiModelInfo, inputTokens, cachedInputTokens, outputTokens, imageInputTokens int64, longContext bool) costPreview {
	promptPrice := model.PromptTextTokenPrice
	cachedPromptPrice := model.CachedPromptTextTokenPrice
	outputPrice := model.CompletionTextTokenPrice
	if longContext {
		if model.PromptTextTokenPriceLongContext != 0 {
			promptPrice = model.PromptTextTokenPriceLongContext
		}
		if model.CachedPromptTextTokenPriceLongContext != 0 {
			cachedPromptPrice = model.CachedPromptTextTokenPriceLongContext
		}
		if model.CompletionTextTokenPriceLongContext != 0 {
			outputPrice = model.CompletionTextTokenPriceLongContext
		}
	}
	var warnings []string
	estimatedCents := float64(0)
	if inputTokens > 0 {
		if promptPrice == 0 {
			warnings = append(warnings, "prompt_text_token_price missing; input text cost omitted")
		}
		estimatedCents += centsForTokens(inputTokens, promptPrice)
	}
	if cachedInputTokens > 0 {
		if cachedPromptPrice == 0 {
			warnings = append(warnings, "cached_prompt_text_token_price missing; cached input cost omitted")
		}
		estimatedCents += centsForTokens(cachedInputTokens, cachedPromptPrice)
	}
	if outputTokens > 0 {
		if outputPrice == 0 {
			warnings = append(warnings, "completion_text_token_price missing; output text cost omitted")
		}
		estimatedCents += centsForTokens(outputTokens, outputPrice)
	}
	if imageInputTokens > 0 {
		if model.PromptImageTokenPrice == 0 {
			warnings = append(warnings, "prompt_image_token_price missing; prompt image token cost omitted")
		}
		estimatedCents += centsForTokens(imageInputTokens, model.PromptImageTokenPrice)
	}
	return costPreview{
		Model:             model.ID,
		InputTokens:       inputTokens,
		CachedInputTokens: cachedInputTokens,
		OutputTokens:      outputTokens,
		ImageInputTokens:  imageInputTokens,
		LongContext:       longContext,
		EstimatedCents:    estimatedCents,
		EstimatedUSD:      estimatedCents / 100,
		PriceFields: map[string]any{
			"unit":                           "USD cents per 100 million tokens",
			"prompt_text_token_price":        promptPrice,
			"cached_prompt_text_token_price": cachedPromptPrice,
			"completion_text_token_price":    outputPrice,
			"prompt_image_token_price":       model.PromptImageTokenPrice,
			"long_context_threshold":         model.LongContextThreshold,
			"source":                         "live model metadata",
		},
		Warnings: warnings,
	}
}

func firstChatContent(data json.RawMessage) string {
	var response struct {
		Choices []struct {
			Message struct {
				Content string `json:"content"`
			} `json:"message"`
		} `json:"choices"`
	}
	if err := json.Unmarshal(data, &response); err != nil || len(response.Choices) == 0 {
		return ""
	}
	return response.Choices[0].Message.Content
}

func modelLooksReasoning(model xaiModelInfo) bool {
	values := append([]string{model.ID}, model.Aliases...)
	for _, value := range values {
		lower := strings.ToLower(value)
		if strings.Contains(lower, "non-reasoning") {
			continue
		}
		if strings.Contains(lower, "reasoning") || strings.Contains(lower, "mini-high") {
			return true
		}
	}
	return false
}

func modelCostSortValue(model xaiModelInfo, task string) float64 {
	switch task {
	case "image":
		return float64(model.ImagePrice)
	case "chat", "reasoning", "vision":
		return float64(model.PromptTextTokenPrice + model.CompletionTextTokenPrice)
	case "embedding":
		return float64(model.PromptTextTokenPrice)
	default:
		return 0
	}
}

func describeUnitCost(model xaiModelInfo, task string) string {
	switch task {
	case "image":
		if model.ImagePrice != 0 {
			return fmt.Sprintf("%d raw image_price", model.ImagePrice)
		}
	case "chat", "reasoning", "vision":
		total := model.PromptTextTokenPrice + model.CompletionTextTokenPrice
		if total != 0 {
			return fmt.Sprintf("%.4f USD / 1M prompt+completion tokens", centsPerMillionFromCentsPer100M(total)/100)
		}
	case "embedding":
		if model.PromptTextTokenPrice != 0 {
			return fmt.Sprintf("%.4f USD / 1M prompt tokens", centsPerMillionFromCentsPer100M(model.PromptTextTokenPrice)/100)
		}
	}
	return "not published"
}

func centsForTokens(tokens, centsPer100M int64) float64 {
	if tokens <= 0 || centsPer100M <= 0 {
		return 0
	}
	return float64(tokens) * float64(centsPer100M) / 100_000_000
}

func centsPerMillionFromCentsPer100M(centsPer100M int64) float64 {
	if centsPer100M <= 0 {
		return 0
	}
	return float64(centsPer100M) / 100
}

func containsString(values []string, target string) bool {
	for _, value := range values {
		if strings.EqualFold(value, target) {
			return true
		}
	}
	return false
}

func uniqueStrings(values []string) []string {
	seen := map[string]bool{}
	out := make([]string, 0, len(values))
	for _, value := range values {
		value = strings.TrimSpace(value)
		if value == "" {
			continue
		}
		key := strings.ToLower(value)
		if seen[key] {
			continue
		}
		seen[key] = true
		out = append(out, value)
	}
	sort.Strings(out)
	return out
}
